command:
$ErrorActionPreference = 'Stop'
$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { throw 'DCOIR_REPO_ROOT is missing.' }
$script = Join-Path $repo 'operator_tools\github_desktop_lane\scripts\New-DcoirAirtableDatabaseHealthExport.ps1'
if (-not (Test-Path -LiteralPath $script -PathType Leaf)) { throw "Airtable export tool not found: $script" }
& $script -ExportMode BoundedRecords -MaxRecordsPerTable 1 -MetadataScope 'All' -ProbeUnsupportedMetadata -TableList 'Work Items' -NoZip
